VALUES
  ('heelevel3-444ca548-moex-00067', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '關於訴願決定，下列敘述何者錯誤？', '["未經法定先行程序而逕行提起訴願之案件，嗣後亦未補正者，應作成不受理之決定", "訴願案件雖符合程式要件，惟實體上無理由，應作成駁回訴願之決定", "對於違法或不當行政處分提起訴願而有理由者，應作成撤銷原處分之決定，並視情形發回原處 分機關另為處分或自為變更原處分", "對於行政機關怠為處分而提起訴願者，應作成確認原處分機關違法之決定，並自為一定之處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00068', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '臺東縣政府函成功鎮公所代為公告現有巷道，甲所有之土地屬於該現有巷道之一部分，下列敘述 何者正確？', '["認定現有巷道之主管機關為臺東縣成功鎮公所", "認定現有巷道之公告，自公告日起第3日生效", "現有巷道之認定，涉及人民財產權之限制，因行政處分未個別送達給相對人甲，故對甲不生效力", "甲不服該公告應向內政部提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00069', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '有關行政法院之管轄，下列敘述何者正確？', '["於高等行政法院增設地方行政訴訟庭，專責部分之第一審通常訴訟程序事件、簡易訴訟程序、 交通裁決、收容聲請等事件", "當事人不服由高等行政法院地方行政訴訟庭所作成之判決，而提出上訴由最高行政法院管轄", "以高等行政法院地方行政訴訟庭為第一審管轄法院之事件，高等行政法院高等行政訴訟庭依通 常訴訟程序審理並為判決者，最高行政法院應以高等行政法院高等行政訴訟庭無管轄權而廢棄 原判決", "聲請人、受裁定人或內政部移民署對高等行政法院地方行政訴訟庭所為收容聲請事件之裁定不 服者，應向最高行政法院為抗告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00070', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '下列何者屬於行政秩序罰？', '["工廠負責人不遵行主管機關依法所為之停工命令，被判處有期徒刑併科罰金", "人民不履行行政法上之義務，遭行政機關科處怠金", "律師違反律師法規定而受懲戒", "電信事業未經核准擅自架設電臺，依法沒入電臺之設備或器材"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
  ('heelevel3-444ca548-moex-00071', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-113-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '關於國家賠償之敘述，下列何者正確？', '["公共設施因設置或管理有欠缺，致人民受損害，如有其他應負責之人，國家不負賠償責任", "於開放之自然公物，經管理機關已就使用該公物為適當之警告，而人民仍從事冒險或具危險性 活動，國家不負損害賠償責任", "國家因採購公務所需之文具造成之損害，亦屬國家賠償責任", "有審判職務之公務員，因執行職務侵害人民自由或權利，就其參與審判或追訴案件犯職務上之 罪，經第一審判決有罪，負國家賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:54+00:00", "source_pdf_sha1": "8dd560c3a46d", "answer_pdf_sha1": "501740119b54", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "329", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
